import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { AGORA_APP_ID } from '../api/config';
import { toast } from 'react-toastify';
import './LiveStream.css';

const LiveStream = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { user } = useSelector((state) => state.auth);

  const channelName = searchParams.get('channel') || `live_${user?._id}_${Date.now()}`;
  const role = searchParams.get('role') || 'host'; // host or audience
  const streamTitle = searchParams.get('title') || 'Live Stream';

  const [isLive, setIsLive] = useState(false);
  const [viewerCount, setViewerCount] = useState(0);
  const [audioMuted, setAudioMuted] = useState(false);
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState('');
  const [showComments, setShowComments] = useState(true);
  const [agoraReady, setAgoraReady] = useState(false);
  const localVideoRef = useRef(null);
  const agoraClientRef = useRef(null);

  useEffect(() => {
    initAgora();
    return () => {
      cleanupAgora();
    };
  // eslint-disable-next-line
  }, []);

  const initAgora = async () => {
    try {
      // Dynamic import of Agora Web SDK
      const AgoraRTC = (await import('agora-rtc-sdk-ng')).default;
      const client = AgoraRTC.createClient({ mode: 'live', codec: 'vp8' });

      if (role === 'host') {
        await client.setClientRole('host');
      } else {
        await client.setClientRole('audience');
      }

      client.on('user-published', async (remoteUser, mediaType) => {
        await client.subscribe(remoteUser, mediaType);
        if (mediaType === 'video') {
          const remoteContainer = document.getElementById('remote-stream');
          if (remoteContainer) {
            remoteUser.videoTrack.play(remoteContainer);
          }
        }
        if (mediaType === 'audio') {
          remoteUser.audioTrack.play();
        }
        setViewerCount((c) => c + 1);
      });

      client.on('user-unpublished', () => {
        setViewerCount((c) => Math.max(0, c - 1));
      });

      client.on('user-left', () => {
        setViewerCount((c) => Math.max(0, c - 1));
      });

      await client.join(AGORA_APP_ID, channelName, null, null);
      agoraClientRef.current = client;

      if (role === 'host') {
        const localAudioTrack = await AgoraRTC.createMicrophoneAudioTrack();
        const localVideoTrack = await AgoraRTC.createCameraVideoTrack({
          encoderConfig: { width: 640, height: 480, frameRate: 30 },
        });
        await client.publish([localAudioTrack, localVideoTrack]);
        const localContainer = document.getElementById('local-stream');
        if (localContainer) {
          localVideoTrack.play(localContainer);
        }
        setIsLive(true);
      }

      setAgoraReady(true);
    } catch (error) {
      console.error('Agora init failed:', error);
      toast.error('Failed to start stream. Check camera/mic permissions.');
    }
  };

  const cleanupAgora = async () => {
    const client = agoraClientRef.current;
    if (client) {
      const localTracks = client.localTracks || [];
      localTracks.forEach((track) => {
        track.stop();
        track.close();
      });
      await client.leave();
    }
  };

  const handleEndStream = async () => {
    await cleanupAgora();
    setIsLive(false);
    toast.success('Stream ended');
    navigate(-1);
  };

  const handleToggleAudio = () => {
    const client = agoraClientRef.current;
    if (client) {
      const audioTrack = client.localTracks?.find((t) => t.trackMediaType === 'audio');
      if (audioTrack) {
        audioTrack.setEnabled(!audioMuted);
        setAudioMuted(!audioMuted);
      }
    }
  };

  const handleSendComment = (e) => {
    e.preventDefault();
    if (!newComment.trim()) return;
    setComments((prev) => [...prev, { id: Date.now(), text: newComment.trim(), user: user?.fullName || 'You' }]);
    setNewComment('');
  };

  return (
    <div className="livestream-page">
      {/* Video area */}
      <div className="livestream-video-area">
        {role === 'host' && <div id="local-stream" className="livestream-local-video" />}
        <div id="remote-stream" className="livestream-remote-video" />

        {/* Overlay info */}
        <div className="livestream-overlay-top">
          {isLive && <span className="livestream-live-badge">● LIVE</span>}
          <span className="livestream-viewer-count">👁 {viewerCount}</span>
          <span className="livestream-title">{streamTitle}</span>
        </div>
      </div>

      {/* Comments */}
      {showComments && (
        <div className="livestream-comments">
          <div className="livestream-comments-list">
            {comments.map((c) => (
              <div key={c.id} className="livestream-comment">
                <span className="livestream-comment-user">{c.user}:</span>
                <span className="livestream-comment-text">{c.text}</span>
              </div>
            ))}
          </div>
          <form className="livestream-comment-form" onSubmit={handleSendComment}>
            <input
              type="text"
              className="livestream-comment-input"
              placeholder="Say something..."
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
            />
            <button type="submit" className="livestream-comment-send">➤</button>
          </form>
        </div>
      )}

      {/* Controls */}
      <div className="livestream-controls">
        <button
          className={`call-control-btn ${audioMuted ? 'active' : ''}`}
          onClick={handleToggleAudio}
        >
          {audioMuted ? '🔇' : '🎤'}
        </button>
        <button
          className="call-control-btn"
          onClick={() => setShowComments(!showComments)}
        >
          💬
        </button>
        {role === 'host' && (
          <button className="call-control-btn call-end-btn" onClick={handleEndStream}>
            ■
          </button>
        )}
      </div>
    </div>
  );
};

export default LiveStream;
